INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-eng-moex-01163', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「消防法」規定之敘述，何者正確？', '["應設消防安全設備之集合住宅，其消防安全設備定期之檢查，得由直轄市、縣（市）消防機關聘用或 委託消防專業人員辦理，經費由地方主管機關編列預算支付，中央主管機關補助；其補助辦法由中央 主管機關另定之", "依建築法第三十條之一申請預審事項，涉及建築物消防安全設備者，主管建築機關應會同消防機關預 為審查", "地面樓層達十層以上建築物、地下建築物及中央主管機關指定之場所，其管理權人應使用附有防焰標 示之地毯、窗簾、布幕、展示用廣告板及其他指定之防焰物品", "地面樓層達五層以上建築物、地下建築物或中央主管機關指定之建築物，其管理權有分屬時，各管理 權人應協議製定共同消防防護計畫，並報請消防機關核備"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01164', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列「緊急廣播設備用揚聲器認可基準」中，有關免會同試驗之敘述，何者有誤？', '["達寬鬆試驗後連續十批第一次試驗均合格者", "累積受驗數量達 1000 個以上", "六個月內未申請個別認可者，該批樣品應即恢復為普通試驗（會同試驗）", "實施免會同試驗時，每半年至少派員會同實施抽驗一次，試驗項目依照型式試驗項目，若試驗不符合 本基準規定時，該批次予以不合格處置，次批並恢復為普通試驗（會同試驗）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01165', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關大型滅火器所充填之滅火劑量規定之敘述，何者有誤？', '["機械泡沫滅火器：20公升以上", "二氧化碳滅火器：45公斤以上", "乾粉滅火器：18公斤以上", "海龍滅火器：10公斤以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01166', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '易燃性液體依物質引火性進行判定，70℃≦閃火點＜200℃者，為第幾石油類？', '["第一石油類", "第二石油類", "第三石油類", "第四石油類"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01167', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '氧化性液體依物質燃燒時間之長短進行判定，其燃燒試驗之標準物質為下列何者？', '["2,4二硝基甲苯（DNT，特級）", "90％硝酸水溶液", "過氧化二苯甲醯（BPO，1級）", "80％硫酸水溶液"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01168', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關消防法罰則規定之敘述，何者有誤？', '["依第六條第一項應設置消防安全設備之供營業使用場所，其管理權人未依規定設置或維護，於發生火 災時致人於死者，處一年以上七年以下有期徒刑，得併科新台幣一百萬元以上五百萬元以下罰金", "依第六條第一項應設置消防安全設備之供營業使用場所，其管理權人未依規定設置或維護，於發生火 災時致重傷者，處六月以上五年以下有期徒刑，得併科新台幣五十萬元以上二百五十萬元以下罰金", "違反第七條第一項規定從事消防安全設備之設計、監造、裝置及檢修者，處新台幣一萬元以上五萬元 以下罰鍰", "違反第十三條規定，經通知限期改善逾期不改善者，處其管理權人新台幣三千元以上一萬五千元以下 罰鍰；經處罰鍰後仍不改善者，得連續處罰"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01169', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '施放以火藥及金屬粉末為主要原料，其成品直徑在多少公分以上或射程在七十五公尺以上之煙火，其負 責人應將煙火種類、數量、施放時間、地點及有關防火、戒備、擬採措施，於三日前向當地消防機關申 請許可？', '["四點五公分", "五點五公分", "六點五公分", "七點五公分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01170', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關防火水幕配管設置規定之敘述，何者正確？', '["可與一般給水管共用", "配管應設於地面下。但其接合部分及閥類設有可供檢查、維修之措施者，不在此限", "配管管系竣工時，應做加壓試驗，試驗壓力為加壓送水裝置全閉揚程一點五倍以上之水壓，須持續兩 小時無漏水現象", "防火水幕設備之配管平時不應充滿水。但自開關閥或選擇閥以下至防火水幕噴頭之配管，不在此限"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01171', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '可燃性高壓氣體儲存場所防爆牆，其混凝土之配合與強度，除應符合CNS三○九○「預拌混凝土」之規 定外，經過二十八日養生後之抗壓強度，其基礎混凝土強度並應符合下列何者？', '["80kgf/cm2以上", "100kgf/cm2以上", "120kgf/cm2以上", "140kgf/cm2以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01172', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關防火水幕設備水源容量與緊急電源之規定敘述，何者正確？', '["儲槽容量未達一萬公秉者，不得小於防護該儲槽連續放水一百二十分鐘之水量", "儲槽容量達一萬公秉以上者，不得小於防護該儲槽連續放水三百六十分鐘之水量", "儲槽容量未達一萬公秉者，供電容量時間為二百四十分鐘", "儲槽容量達一萬公秉以上者，供電容量時間為四百八十分鐘"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
